/* Астро Компас — вградени шрифтове за PDF (DejaVu Sans, subset).
 * Регистрира "AstroSans" (normal + bold) в jsPDF, за да се изписват
 * кирилица и астрологичните символи в наталния PDF.
 * Съдържа само нужните глифи — генериран автоматично.
 */
(function () {
  if (typeof window === "undefined" || !window.jspdf) return;
  var REG = "";
  var BOLD = "";
  function register(jsPDFAPI) {
    jsPDFAPI.events.push(["addFonts", function () {
      this.addFileToVFS("AstroSans-Regular.ttf", REG);
      this.addFont("AstroSans-Regular.ttf", "AstroSans", "normal");
      this.addFileToVFS("AstroSans-Bold.ttf", BOLD);
      this.addFont("AstroSans-Bold.ttf", "AstroSans", "bold");
    }]);
  }
  register(window.jspdf.jsPDF.API);
})();
